// Extract message timestamp from Slack chat.postMessage response.
// The ts is used for threading: all subsequent pipeline notifications
// (Council, implement, done) reply under this initial message.
const response = $input.first().json;
const ts = response?.ts ?? '';
const ok = response?.ok ?? false;

if (!ok) {
  // Slack call failed (token missing, channel wrong, etc.)
  // Non-blocking: dispatch proceeds without thread_ts
  console.log('Slack Bot API response not ok — threading disabled for this run');
}

return [{ json: { ts, ok } }];
